import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"掌心友","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/掌心友.md","filePath":"4.资源分区/6.技艺及称号/杂项/掌心友.md"}'),s={name:"4.资源分区/6.技艺及称号/杂项/掌心友.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"掌心友",tabindex:"-1"},[p("掌心友 "),r("a",{class:"header-anchor",href:"#掌心友","aria-label":'Permalink to "掌心友"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="掌心友-1" tabindex="-1">掌心友 <a class="header-anchor" href="#掌心友-1" aria-label="Permalink to &quot;掌心友&quot;">​</a></h1><p>掌心友<br> 价格：D+1000<br> 分类：技艺<br> ——————<br> “事情好多啊好多...社交什么的也一塌糊涂，要人陪没人陪的...都是我当观众”<br> “明明事情都很少，但就是提不起性子来干完！偏偏有的地方还老是提醒我...”<br> 假期的又一个深夜，已是凌晨二点，翻来覆去的某人是知晓自己睡不好了，但还是要睡<br> 正是郁闷至极，又寻不得几号朋友亲人述说，强行入睡只会令头胀痛无比，于是觉也无了</p><p>“......哦呵呵，你，你看起来很孤独，忧郁”<br> “你，你需要陪，陪伴吗？不说话，不说，我就当，当你没意见”<br> 怪异，口齿不清的声音从脑海中传出，有些令人崩溃，心生寒意<br> 于是艰难起身，把灯开起，起坐左视右顾。见得一切安好就又躺下，这一闹，倒是力竭昏迷。</p><p>一夜就又是如此渡过，人精疲力尽，再度醒来已是午时<br> “开什么玩笑，我没睡醒吗？！”<br> “不出小区，没有异象，连新闻都没报道的...我的手这是怎么了额啊啊啊！？”<br> ——————<br> 效果：<br> 购买时选定在左手/右手/所具有的某一肢体，之后对应肢体的掌心将长出一张具有尖牙利齿的口，其视为武器伤害6L的天生-肉搏武器，具有【破甲1】，使用专业为武技-掌心口，造成物理-穿刺伤害。当你使用其他肢体的武器进行近战攻击时，若掌心友对应的肢体不持有武器，则可将掌心友的基础属性一半与所有特性加入攻击中。</p><p>掌心友能够发出的音色与你本人的初始音色相同，在一些情况下可以代替你原有的口部发声，或是作为备选口部进食。但由于作为概念上的“口”，所以其不可避免的会受到沉默或针对口部才能生效的等效果的影响，从而无法发挥如上的效果，但仍可作为天生武器使用。</p><p>同样的，掌心友所在的肢体陷入肢体妨碍的毁灭状态时，则失去其全部的能力，包括作为天生武器的能力。</p><p>————【下属技艺】——<br> 善口技者<br> 价格：D+500<br> “都说最近新来了一位手偶戏大师...近来那些学者和专家可没少去找他麻烦来着”<br> “可不是嘛，虽然演的剧本很烂，但这个天份和游刃有余确实也得让我喊一句，这诗人吗？”<br> 事实上，掌心友能干的完全不止这点事，但想要不引起公众恐慌把你抓起来研究，也只能让它背地里当你的嘴替或者背景音播放器...虽然你想着这么干本身就很危险了，但介于你身处电话订阅就能获取这等强化的世界，似乎又有点合理性不是？但别可带去其他世界也这么玩，牢记啊牢记。</p><p>当你进行哄骗/威吓相关检定时，可以借助掌心友给自己造势，对于本次检定而言额外获得2点附加成功。<br> ————<br> 亲手品鉴<br> 价格：D+1000<br> “张开...紧握...咬合，最后是扯开”<br> 心中默念着要领，只是片刻，你的手中就多了一块鲜红的肉块...掌心友正在津津有味的吃着，还是你吃得津津有味？<br> 不过这都不是重点，受害者还醒着呢...</p><p>当你进行一次使用掌心友进行或有掌心友参与的攻击时，命中后额外造成1点不可豁免的流血点数。<br> ————<br> 舌到擒来<br> 价格：C+1000<br> 尖牙利齿还不是掌心友的极限...既然是口，怎么能没有尝味的舌？<br> 只是被困于此，每日都只能感觉到血肉在面前而不可及...于是便不断伸长，伸长自己的舌。<br> 而当它的长舌品尝到的那天，主人才恍然大悟，自己所作所为还可为寻常人否？</p><p>当你进行绊摔/拖拽/擒抱时，若使用掌心友参与则本次行为的触及范围增加4m，并令本次检定获得【9加骰】。<br> 而进行擒抱时，仅需要占用掌心友所在的肢体便可满足擒抱要求，而非原本的至少两条肢体。</p><p>在画风上，这是你的掌心突出一条鲜红且有筋道的长舌试图捆住对方。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
